  sm <- methods::new(SMapProjection)
  sm$embedding_dimension <- 2L
  sm$theta               <- 1.0

  #' @description Test that SMapProjection::predict throws when given a non-existent library id.
  expect_error(sm$predict(9999L, test_de$get_id()))

  clear()
})

